arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

IDataView allData = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age),
        nameof(ChurnInput.Income),
        "RegionEncoded",
        nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(ChurnInput.Churned),
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions,
    labelColumnName: nameof(ChurnInput.Churned));
Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
    $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model to disk so PredictionEnginePool can load it
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

// Register the thread-safe pooled prediction engine
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest req) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score
    });
});

app.Run();

// --- Data models ---

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class ChurnOutput
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

